test_that("ci_tree_control stores greedy tree controls", {
  default_ctrl <- ci_tree_control()
  ctrl <- ci_tree_control(
    minsplit = 10,
    minbucket = 3,
    minprob = 0.1,
    maxdepth = 2,
    min_gain = 0.01,
    min_relative_gain = 0.05,
    mtry = 1
  )

  expect_equal(ctrl$minsplit, 10)
  expect_equal(ctrl$minbucket, 3)
  expect_equal(ctrl$minprob, 0.1)
  expect_equal(ctrl$maxdepth, 2)
  expect_equal(ctrl$min_gain, 0.01)
  expect_equal(ctrl$min_relative_gain, 0.05)
  expect_equal(ctrl$mtry, 1)
  expect_equal(ctrl$split_engine, "cpp")
  expect_equal(ctrl$factor_split, "auto")
  expect_equal(
    ctrl$max_factor_levels_partition,
    default_ctrl$max_factor_levels_partition
  )
  expect_equal(ctrl$max_factor_partitions, default_ctrl$max_factor_partitions)
})

test_that(".ci_tree_normalize_control accepts shared ctree controls", {
  ctrl <- ineqTrees::.ci_tree_normalize_control(
    partykit::ctree_control(
      minsplit = 5,
      minbucket = 2,
      minprob = 0,
      maxdepth = 1,
      mtry = 1
    )
  )

  expect_equal(ctrl$minsplit, 5L)
  expect_equal(ctrl$minbucket, 2L)
  expect_equal(ctrl$minprob, 0)
  expect_equal(ctrl$maxdepth, 1)
  expect_equal(ctrl$mtry, 1L)
  expect_equal(ctrl$split_engine, "cpp")
})

